INSERT INTO `ie_kpi` VALUES (1,'avg_qa_score','Avg QA Score','Average QA score across all finalized submissions.','Quality','SQL','AVG(total_score) WHERE status = FINALIZED','submission','PERCENT',1,'UP_IS_GOOD',NULL,1,1,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(2,'audits_assigned','Audits Assigned','Expected audits based on pace targets in KPI thresholds.','Quality','DERIVED','goal_value_per_business_day * business_days_in_period','ie_kpi_threshold + business_calendar_days','NUMBER',0,'NEUTRAL',NULL,1,2,'2026-04-07 09:52:42','2026-04-07 16:43:26',NULL),(3,'audits_completed','Audits Completed','Total QA audits finalized this period.','Quality','SQL','COUNT WHERE status = FINALIZED AND submitted_at IN period','submission','NUMBER',0,'UP_IS_GOOD',NULL,1,3,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(4,'audit_completion_rate','Audit Completion %','Percentage of expected audits completed.','Quality','DERIVED','audits_completed / audits_assigned x 100','submission,ie_kpi_threshold','PERCENT',1,'UP_IS_GOOD',NULL,1,4,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(5,'dispute_rate','Dispute Rate','Percentage of finalized submissions disputed.','Quality','SQL','COUNT(disputes) / COUNT(finalized) x 100','dispute,submission','PERCENT',1,'DOWN_IS_GOOD',NULL,1,5,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(6,'dispute_upheld_rate','Dispute Upheld Rate','Of resolved disputes, percentage upheld in agent favor.','Quality','SQL','COUNT(UPHELD) / COUNT(resolved) x 100','dispute','PERCENT',1,'DOWN_IS_GOOD',NULL,1,6,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(7,'dispute_not_upheld_rate','Dispute Rejected Rate','Percentage of resolved disputes rejected.','Quality','SQL','COUNT(REJECTED) / COUNT(resolved) x 100','dispute','PERCENT',1,'NEUTRAL',NULL,1,7,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(8,'dispute_adjusted_rate','Dispute Adjusted Rate','Submissions where dispute led to score adjustment.','Quality','SQL','COUNT(ADJUSTED) / COUNT(finalized) x 100','dispute,submission','PERCENT',1,'DOWN_IS_GOOD',NULL,1,8,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(9,'avg_dispute_resolution_time','Avg Resolution Time','Average days from dispute creation to resolution.','Quality','SQL','AVG(resolved_at - created_at) in days','dispute','NUMBER',1,'DOWN_IS_GOOD',NULL,1,9,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(10,'critical_fail_rate','Critical Fail Rate','Evaluations where an auto-fail question was triggered.','Quality','SQL','COUNT(auto-fail) / COUNT(submissions) x 100','submission_answer,form_question','PERCENT',1,'DOWN_IS_GOOD',NULL,1,10,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(11,'time_to_audit','Time to Audit','Average days from call date to QA audit completion.','Quality','SQL','AVG(submitted_at - call_date) in days','submission','NUMBER',1,'DOWN_IS_GOOD',NULL,1,11,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(12,'qa_score_trend','QA Score Trend','Directional trend of average QA scores over the selected period.','Quality','DERIVED','delta of avg_qa_score vs prior period','submission','PERCENT',1,'UP_IS_GOOD',NULL,1,12,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(13,'coaching_sessions_assigned','Sessions Assigned','Expected sessions based on pace targets x active agents x weeks.','Coaching','DERIVED','pace_per_agent x active_agents x weeks_in_period','ie_kpi_threshold,user','NUMBER',0,'NEUTRAL',NULL,1,13,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(14,'coaching_sessions_completed','Sessions Completed','Coaching sessions reaching COMPLETED or CLOSED status.','Coaching','SQL','COUNT WHERE status IN (COMPLETED,CLOSED) AND completed_at IN period','coaching_session','NUMBER',0,'UP_IS_GOOD',NULL,1,14,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(15,'coaching_completion_rate','Coaching Completion %','Percentage of expected coaching sessions completed.','Coaching','DERIVED','sessions_completed / sessions_assigned x 100','coaching_session,ie_kpi_threshold','PERCENT',1,'UP_IS_GOOD',NULL,1,15,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(16,'coaching_delivery_rate','Coaching Delivery','Scheduled sessions that were actually delivered.','Coaching','SQL','COUNT(delivered_at IS NOT NULL) / COUNT(sessions) x 100','coaching_session','PERCENT',1,'UP_IS_GOOD',NULL,1,16,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(17,'coaching_cadence','Coaching Cadence','Percentage of target sessions delivered based on expected frequency.','Coaching','DERIVED','delivered_sessions / (agents x expected_per_period) x 100','coaching_session,ie_kpi_threshold','PERCENT',1,'UP_IS_GOOD',NULL,1,17,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(18,'avg_days_to_close_coaching','Avg Days to Close','Average days from coaching session creation to completion.','Coaching','SQL','AVG(completed_at - created_at) in days','coaching_session','NUMBER',1,'DOWN_IS_GOOD',NULL,1,18,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(19,'followup_compliance_rate','Follow-Up Compliance','Sessions requiring follow-up where follow-up was completed on time.','Coaching','SQL','COUNT(on-time) / COUNT(required) x 100','coaching_session','PERCENT',1,'UP_IS_GOOD',NULL,1,19,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(20,'time_to_coaching','Time to Coaching','Average days from low QA score to coaching session creation.','Coaching','SQL','AVG(coaching.created_at - submission.submitted_at) in days','coaching_session,submission','NUMBER',1,'DOWN_IS_GOOD',NULL,1,20,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(21,'quiz_pass_rate','Quiz Pass Rate','Percentage of quiz attempts resulting in a passing score.','Quiz','SQL','COUNT(passed=true) / COUNT(attempts) x 100','quiz_attempt','PERCENT',1,'UP_IS_GOOD',NULL,1,21,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(22,'avg_quiz_score','Avg Quiz Score','Average score across all quiz attempts.','Quiz','SQL','AVG(quiz_attempt.score)','quiz_attempt','PERCENT',1,'UP_IS_GOOD',NULL,1,22,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(23,'avg_attempts_to_pass','Avg Attempts to Pass','Average quiz attempts before passing.','Quiz','SQL','AVG(attempts per quiz until pass)','quiz_attempt','NUMBER',1,'DOWN_IS_GOOD',NULL,1,23,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(24,'total_writeups_issued','Write-Ups Issued','Total write-ups created this period.','Discipline','SQL','COUNT WHERE created_at IN period','write_up','NUMBER',0,'DOWN_IS_GOOD',NULL,1,24,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(25,'writeup_rate','Write-Up Rate','Write-ups per 100 employees per month.','Discipline','DERIVED','COUNT(write_ups) / COUNT(active_employees) x 100','write_up,user','NUMBER',1,'NEUTRAL',NULL,1,25,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(26,'escalation_rate','Escalation Rate','Write-ups that escalated from verbal to written or written to final.','Discipline','SQL','COUNT(escalated) / COUNT(write_ups) x 100','write_up,write_up_prior_discipline','PERCENT',1,'DOWN_IS_GOOD',NULL,1,26,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(27,'repeat_offender_rate','Repeat Offender Rate','Agents who receive another write-up within 90 days.','Discipline','SQL','COUNT(agents with 2+ write-ups in 90 days) / COUNT(agents with write-ups) x 100','write_up','PERCENT',1,'DOWN_IS_GOOD',NULL,1,27,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL),(28,'writeup_resolution_rate','Write-Up Resolution','Percentage of write-ups reaching CLOSED status.','Discipline','SQL','COUNT(status=CLOSED) / COUNT(write_ups) x 100','write_up','PERCENT',1,'UP_IS_GOOD',NULL,1,28,'2026-04-07 09:52:42','2026-04-07 09:52:42',NULL);

